#include<bits/stdc++.h>
using namespace std;
bool v[1001];
int b[1001], n, k;
void dfs(int x) {
	if (x > k) {
		for (int i = 1; i <= k; i++) {
			cout << b[i]<<' ';
		}
		cout << '\n';
		return;
	}
	for (int i = 1; i <= n; i++) {
		if (!v[i]) {
			b[x] = i;
			v[i] = 1;
			dfs(x + 1);
			v[i]=0;
		}
	}
}
int main() {
	cin >> n>>k;
	dfs(1);
	return 0;
}
